sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
    if (isLoading) return;
    if (!newValue) return;

    var units = parseInt(newValue);
    if (isNaN(units) || units <= 0) {
        g_form.showFieldMsg('units_required', 'Units Required must be greater than zero.', 'error');
    } else {
        g_form.hideFieldMsg('units_required');
    }
}
